const test = require("node:test");
const assert = require("node:assert");
const { parseDuration } = require("../src/duration.js");

test("hours and minutes combine", () => {
  assert.strictEqual(parseDuration("1h30m"), 5400);
});

test("minutes only", () => {
  assert.strictEqual(parseDuration("90m"), 5400);
});

test("hours only", () => {
  assert.strictEqual(parseDuration("2h"), 7200);
});

test("seconds only", () => {
  assert.strictEqual(parseDuration("45s"), 45);
});

test("all three units", () => {
  assert.strictEqual(parseDuration("1h1m1s"), 3661);
});

test("empty string throws", () => {
  assert.throws(() => parseDuration(""));
});

test("invalid format throws", () => {
  assert.throws(() => parseDuration("abc"));
});

test("whitespace is not allowed", () => {
  assert.throws(() => parseDuration("1h 30m"));
});
